// ポインタ比較のうち、NULLポインタ定数・互換ポインタ・明示的に
// ポインタへ変換した値を使う合法形がE3122にならないことを確認する。
//
// 合法条件:
//   - `p == 0` (NULL ポインタ定数)
//   - `p == (void*)5` (明示的にポインタへ変換済み)
//   - 両辺ポインタ、両辺整数 (符号比較や signed/unsigned は別経路で扱う)
//
// 非ゼロ整数との直接比較は別のcompile-fail caseでE3122を確認する。
#include <assert.h>

int main(void) {
    int x = 42;
    int *p = &x;

    /* (a) NULL ポインタ定数 (0) との比較 — 合法 */
    int *q = 0;
    if (p == 0) {}
    if (q != 0) {}
    if (0 == p) {}

    /* (b) ポインタ同士の比較 — 警告なし */
    if (p == q) {}
    if (p != q) {}

    /* (c) 明示キャスト経由 — 警告なし */
    if (p == (int *)0x1000) {}

    /* (d) 整数同士の比較 — 警告なし */
    int a = 5, b = 5;
    if (a == b) {}
    if (a != 100) {}

    assert(*p == 42);
    return 0;
}
